import React from 'react';

const Footer: React.FC = () => {
  return (
    <footer className="fixed bottom-4 left-6 z-50">
      <div className="flex items-center gap-2 text-slate-500 text-sm font-light tracking-widest opacity-60 hover:opacity-100 transition-opacity">
        <span className="w-2 h-2 bg-curang-primary rounded-full animate-pulse"></span>
        DEVELOPER <span className="text-curang-primary font-bold">정혁신</span>
      </div>
    </footer>
  );
};

export default Footer;

import React, { useState, useEffect, useRef } from 'react';
import { StepType, StepStatus, ProcessingStep } from './types';
import { generateStepContent } from './services/geminiService';
import StepVisualizer from './components/StepVisualizer';
import ResultDisplay from './components/ResultDisplay';
import Footer from './components/Footer';
import { Sparkles, Play, Briefcase } from 'lucide-react';

const INITIAL_STEPS: ProcessingStep[] = [
  { id: StepType.SEARCH, label: '광고 소재 찾기', description: '트렌드 분석 및 훅(Hook) 발굴', status: StepStatus.IDLE },
  { id: StepType.PLANNING, label: '광고 소재 기획', description: '비주얼 컨셉 및 카피라이팅', status: StepStatus.IDLE },
  { id: StepType.CHANNELS, label: '효과적인 마케팅 채널', description: '미디어 믹스 및 타겟팅', status: StepStatus.IDLE },
  { id: StepType.STRATEGY, label: '광고 소재 마케팅 전략', description: '예산 배분 및 KPI 설정', status: StepStatus.IDLE },
];

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [steps, setSteps] = useState<ProcessingStep[]>(INITIAL_STEPS);
  const [currentStepIndex, setCurrentStepIndex] = useState(-1);
  const [finalResult, setFinalResult] = useState<string>('');
  const [productName, setProductName] = useState('큐랑 스펙트라 캐리어'); // Default preset
  const [productFeatures, setProductFeatures] = useState('초경량 폴리카보네이트, 360도 무소음 휠, 스마트 저울 내장, 충격 방지 코너 가드, 모던한 메탈릭 컬러');

  const containerRef = useRef<HTMLDivElement>(null);

  // Auto-runner logic
  useEffect(() => {
    if (!hasStarted || currentStepIndex === -1) return;

    const executeStep = async () => {
      const currentStep = steps[currentStepIndex];

      // Update status to processing
      setSteps(prev => prev.map((s, i) => i === currentStepIndex ? { ...s, status: StepStatus.PROCESSING } : s));

      try {
        // Collect context from previous steps for continuity
        let previousContext = "";
        for (let i = 0; i < currentStepIndex; i++) {
           previousContext += `\n\n--- [${steps[i].label} 결과] ---\n${steps[i].result || ''}`;
        }

        // Call Gemini
        const result = await generateStepContent(
          currentStep.id, 
          productName, 
          productFeatures, 
          previousContext
        );

        // Update step with result and completed status
        setSteps(prev => prev.map((s, i) => i === currentStepIndex ? { ...s, status: StepStatus.COMPLETED, result: result } : s));

        // Move to next step or finish
        if (currentStepIndex < steps.length - 1) {
          setTimeout(() => setCurrentStepIndex(prev => prev + 1), 800); // Small delay for visual effect
        } else {
          // Compile final result
          const compiledMarkdown = `
# 🧳 큐랑(Curang) DCO 마케팅 솔루션
> **Model**: Gemini 3 Pro Preview | **Target**: ${productName}

---
${previousContext}
\n\n--- [${currentStep.label} 결과] ---\n${result}
          `;
          setFinalResult(compiledMarkdown);
          setTimeout(() => {
            containerRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
          }, 500);
        }
      } catch (error) {
        console.error("Step execution failed", error);
        setSteps(prev => prev.map((s, i) => i === currentStepIndex ? { ...s, status: StepStatus.ERROR } : s));
      }
    };

    executeStep();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentStepIndex, hasStarted]);

  const handleStart = () => {
    setHasStarted(true);
    setCurrentStepIndex(0);
  };

  return (
    <div className="min-h-screen font-sans text-white bg-curang-dark selection:bg-curang-primary selection:text-white relative overflow-hidden">
      {/* Background Decor */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none z-0">
         <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-curang-primary/10 rounded-full blur-[100px] animate-pulse-slow"></div>
         <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-indigo-900/20 rounded-full blur-[80px]"></div>
      </div>

      {/* Main Content */}
      <div className="relative z-10 container mx-auto px-4 py-12 max-w-6xl">

        {/* Header */}
        <header className="mb-16 text-center">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-slate-800/50 border border-slate-700 text-xs text-curang-primary font-bold tracking-widest mb-6">
            <Sparkles className="w-3 h-3" />
            POWERED BY GEMINI 3 PRO PREVIEW
          </div>
          <h1 className="text-5xl md:text-6xl font-black tracking-tight mb-4 text-transparent bg-clip-text bg-gradient-to-br from-white via-slate-200 to-slate-500">
            큐랑 DCO AI
          </h1>
          <p className="text-slate-400 text-lg md:text-xl font-light max-w-2xl mx-auto">
            세계 최고의 퍼포먼스 마케터 페르소나와 함께<br/>
            가장 강력한 광고 소재와 마케팅 전략을 자동으로 생성합니다.
          </p>
        </header>

        {!hasStarted ? (
          /* Input Section */
          <div className="max-w-2xl mx-auto bg-slate-800/50 backdrop-blur-md p-8 rounded-3xl border border-slate-700 shadow-2xl">
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">제품명 (Build Name)</label>
                <div className="relative">
                  <Briefcase className="absolute left-4 top-3.5 text-slate-500 w-5 h-5" />
                  <input 
                    type="text" 
                    value={productName}
                    onChange={(e) => setProductName(e.target.value)}
                    className="w-full bg-slate-900/50 border border-slate-700 rounded-xl py-3 pl-12 pr-4 text-white focus:ring-2 focus:ring-curang-primary focus:border-transparent transition-all outline-none"
                    placeholder="예: 큐랑 보야저 프로"
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">제품 특징 및 핵심 정보</label>
                <textarea 
                  value={productFeatures}
                  onChange={(e) => setProductFeatures(e.target.value)}
                  className="w-full bg-slate-900/50 border border-slate-700 rounded-xl py-3 px-4 text-white h-32 focus:ring-2 focus:ring-curang-primary focus:border-transparent transition-all outline-none resize-none"
                  placeholder="제품의 주요 특징을 입력하세요..."
                />
              </div>
              <button 
                onClick={handleStart}
                className="w-full group relative bg-gradient-to-r from-curang-primary to-cyan-600 hover:to-cyan-500 text-white font-bold py-4 rounded-xl shadow-[0_0_20px_rgba(14,165,233,0.3)] hover:shadow-[0_0_30px_rgba(14,165,233,0.5)] transition-all transform hover:-translate-y-1"
              >
                <div className="flex items-center justify-center gap-2">
                  <span>솔루션 자동 실행</span>
                  <Play className="w-5 h-5 fill-current" />
                </div>
              </button>
            </div>
          </div>
        ) : (
          /* Execution & Results Section */
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8" ref={containerRef}>

            {/* Left Column: Process Visualizer (Sticky) */}
            <div className="lg:col-span-4 lg:sticky lg:top-8 h-fit space-y-8">
              <div className="bg-slate-800/30 backdrop-blur-sm p-6 rounded-2xl border border-slate-700/50">
                <h3 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-curang-accent animate-ping"></div>
                  실시간 분석 중
                </h3>
                <StepVisualizer steps={steps} currentStepIndex={currentStepIndex} />
              </div>

              {/* Context Info Card */}
              <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
                <h4 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-2">Target Product</h4>
                <p className="text-lg font-bold text-white">{productName}</p>
                <p className="text-sm text-slate-500 mt-2 line-clamp-3">{productFeatures}</p>
              </div>
            </div>

            {/* Right Column: Dynamic Results */}
            <div className="lg:col-span-8 space-y-8">
               {finalResult ? (
                 <div className="animate-[slideIn_0.5s_ease-out]">
                   <ResultDisplay content={finalResult} />
                   <div className="mt-8 text-center">
                     <button 
                       onClick={() => window.location.reload()}
                       className="px-8 py-3 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded-full text-slate-300 hover:text-white transition-colors"
                     >
                       새로운 전략 생성하기
                     </button>
                   </div>
                 </div>
               ) : (
                 <div className="flex flex-col items-center justify-center h-[500px] text-center p-8 border-2 border-dashed border-slate-800 rounded-3xl bg-slate-900/20">
                    <div className="w-24 h-24 mb-6 rounded-full bg-slate-800 flex items-center justify-center animate-glow">
                      <BrainCircuit className="w-12 h-12 text-curang-primary animate-pulse" />
                    </div>
                    <h2 className="text-2xl font-bold text-white mb-2">
                      Gemini 3 Pro가 사고 중입니다...
                    </h2>
                    <p className="text-slate-400 max-w-md">
                      {steps[currentStepIndex]?.label} 단계를 수행하고 있습니다.<br/>
                      최고의 마케팅 퍼포먼스를 위해 심도 있는 분석을 진행 중입니다.
                    </p>
                 </div>
               )}
            </div>
          </div>
        )}
      </div>

      <Footer />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { StepType, StepStatus, ProcessingStep } from './types';
import { generateStepContent } from './services/geminiService';
import StepVisualizer from './components/StepVisualizer';
import ResultDisplay from './components/ResultDisplay';
import Footer from './components/Footer';
import { Sparkles, Play, Briefcase, BrainCircuit } from 'lucide-react';

const INITIAL_STEPS: ProcessingStep[] = [
  { id: StepType.SEARCH, label: '광고 소재 찾기', description: '트렌드 분석 및 훅(Hook) 발굴', status: StepStatus.IDLE },
  { id: StepType.PLANNING, label: '광고 소재 기획', description: '비주얼 컨셉 및 카피라이팅', status: StepStatus.IDLE },
  { id: StepType.CHANNELS, label: '효과적인 마케팅 채널', description: '미디어 믹스 및 타겟팅', status: StepStatus.IDLE },
  { id: StepType.STRATEGY, label: '광고 소재 마케팅 전략', description: '예산 배분 및 KPI 설정', status: StepStatus.IDLE },
];

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [steps, setSteps] = useState<ProcessingStep[]>(INITIAL_STEPS);
  const [currentStepIndex, setCurrentStepIndex] = useState(-1);
  const [finalResult, setFinalResult] = useState<string>('');
  const [productName, setProductName] = useState('큐랑 스펙트라 캐리어'); // Default preset
  const [productFeatures, setProductFeatures] = useState('초경량 폴리카보네이트, 360도 무소음 휠, 스마트 저울 내장, 충격 방지 코너 가드, 모던한 메탈릭 컬러');

  const containerRef = useRef<HTMLDivElement>(null);

  // Auto-runner logic
  useEffect(() => {
    if (!hasStarted || currentStepIndex === -1) return;

    const executeStep = async () => {
      const currentStep = steps[currentStepIndex];

      // Update status to processing
      setSteps(prev => prev.map((s, i) => i === currentStepIndex ? { ...s, status: StepStatus.PROCESSING } : s));

      try {
        // Collect context from previous steps for continuity
        let previousContext = "";
        for (let i = 0; i < currentStepIndex; i++) {
           previousContext += `\n\n--- [${steps[i].label} 결과] ---\n${steps[i].result || ''}`;
        }

        // Call Gemini
        const result = await generateStepContent(
          currentStep.id, 
          productName, 
          productFeatures, 
          previousContext
        );

        // Update step with result and completed status
        setSteps(prev => prev.map((s, i) => i === currentStepIndex ? { ...s, status: StepStatus.COMPLETED, result: result } : s));

        // Move to next step or finish
        if (currentStepIndex < steps.length - 1) {
          setTimeout(() => setCurrentStepIndex(prev => prev + 1), 800); // Small delay for visual effect
        } else {
          // Compile final result
          const compiledMarkdown = `
# 🧳 큐랑(Curang) DCO 마케팅 솔루션
> **Model**: Gemini 3 Pro Preview | **Target**: ${productName}

---
${previousContext}
\n\n--- [${currentStep.label} 결과] ---\n${result}
          `;
          setFinalResult(compiledMarkdown);
          setTimeout(() => {
            containerRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
          }, 500);
        }
      } catch (error) {
        console.error("Step execution failed", error);
        setSteps(prev => prev.map((s, i) => i === currentStepIndex ? { ...s, status: StepStatus.ERROR } : s));
      }
    };

    executeStep();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentStepIndex, hasStarted]);

  const handleStart = () => {
    setHasStarted(true);
    setCurrentStepIndex(0);
  };

  return (
    <div className="min-h-screen font-sans text-white bg-curang-dark selection:bg-curang-primary selection:text-white relative overflow-hidden">
      {/* Background Decor */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none z-0">
         <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-curang-primary/10 rounded-full blur-[100px] animate-pulse-slow"></div>
         <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-indigo-900/20 rounded-full blur-[80px]"></div>
      </div>

      {/* Main Content */}
      <div className="relative z-10 container mx-auto px-4 py-12 max-w-6xl">

        {/* Header */}
        <header className="mb-16 text-center">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-slate-800/50 border border-slate-700 text-xs text-curang-primary font-bold tracking-widest mb-6">
            <Sparkles className="w-3 h-3" />
            POWERED BY GEMINI 3 PRO PREVIEW
          </div>
          <h1 className="text-5xl md:text-6xl font-black tracking-tight mb-4 text-transparent bg-clip-text bg-gradient-to-br from-white via-slate-200 to-slate-500">
            큐랑 DCO AI
          </h1>
          <p className="text-slate-400 text-lg md:text-xl font-light max-w-2xl mx-auto">
            세계 최고의 퍼포먼스 마케터 페르소나와 함께<br/>
            가장 강력한 광고 소재와 마케팅 전략을 자동으로 생성합니다.
          </p>
        </header>

        {!hasStarted ? (
          /* Input Section */
          <div className="max-w-2xl mx-auto bg-slate-800/50 backdrop-blur-md p-8 rounded-3xl border border-slate-700 shadow-2xl">
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">제품명 (Build Name)</label>
                <div className="relative">
                  <Briefcase className="absolute left-4 top-3.5 text-slate-500 w-5 h-5" />
                  <input 
                    type="text" 
                    value={productName}
                    onChange={(e) => setProductName(e.target.value)}
                    className="w-full bg-slate-900/50 border border-slate-700 rounded-xl py-3 pl-12 pr-4 text-white focus:ring-2 focus:ring-curang-primary focus:border-transparent transition-all outline-none"
                    placeholder="예: 큐랑 보야저 프로"
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">제품 특징 및 핵심 정보</label>
                <textarea 
                  value={productFeatures}
                  onChange={(e) => setProductFeatures(e.target.value)}
                  className="w-full bg-slate-900/50 border border-slate-700 rounded-xl py-3 px-4 text-white h-32 focus:ring-2 focus:ring-curang-primary focus:border-transparent transition-all outline-none resize-none"
                  placeholder="제품의 주요 특징을 입력하세요..."
                />
              </div>
              <button 
                onClick={handleStart}
                className="w-full group relative bg-gradient-to-r from-curang-primary to-cyan-600 hover:to-cyan-500 text-white font-bold py-4 rounded-xl shadow-[0_0_20px_rgba(14,165,233,0.3)] hover:shadow-[0_0_30px_rgba(14,165,233,0.5)] transition-all transform hover:-translate-y-1"
              >
                <div className="flex items-center justify-center gap-2">
                  <span>솔루션 자동 실행</span>
                  <Play className="w-5 h-5 fill-current" />
                </div>
              </button>
            </div>
          </div>
        ) : (
          /* Execution & Results Section */
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8" ref={containerRef}>

            {/* Left Column: Process Visualizer (Sticky) */}
            <div className="lg:col-span-4 lg:sticky lg:top-8 h-fit space-y-8">
              <div className="bg-slate-800/30 backdrop-blur-sm p-6 rounded-2xl border border-slate-700/50">
                <h3 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-curang-accent animate-ping"></div>
                  실시간 분석 중
                </h3>
                <StepVisualizer steps={steps} currentStepIndex={currentStepIndex} />
              </div>

              {/* Context Info Card */}
              <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
                <h4 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-2">Target Product</h4>
                <p className="text-lg font-bold text-white">{productName}</p>
                <p className="text-sm text-slate-500 mt-2 line-clamp-3">{productFeatures}</p>
              </div>
            </div>

            {/* Right Column: Dynamic Results */}
            <div className="lg:col-span-8 space-y-8">
               {finalResult ? (
                 <div className="animate-[slideIn_0.5s_ease-out]">
                   <ResultDisplay content={finalResult} />
                   <div className="mt-8 text-center">
                     <button 
                       onClick={() => window.location.reload()}
                       className="px-8 py-3 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded-full text-slate-300 hover:text-white transition-colors"
                     >
                       새로운 전략 생성하기
                     </button>
                   </div>
                 </div>
               ) : (
                 <div className="flex flex-col items-center justify-center h-[500px] text-center p-8 border-2 border-dashed border-slate-800 rounded-3xl bg-slate-900/20">
                    <div className="w-24 h-24 mb-6 rounded-full bg-slate-800 flex items-center justify-center animate-glow">
                      <BrainCircuit className="w-12 h-12 text-curang-primary animate-pulse" />
                    </div>
                    <h2 className="text-2xl font-bold text-white mb-2">
                      Gemini 3 Pro가 사고 중입니다...
                    </h2>
                    <p className="text-slate-400 max-w-md">
                      {steps[currentStepIndex]?.label} 단계를 수행하고 있습니다.<br/>
                      최고의 마케팅 퍼포먼스를 위해 심도 있는 분석을 진행 중입니다.
                    </p>
                 </div>
               )}
            </div>
          </div>
        )}
      </div>

      <Footer />
    </div>
  );
};

export default App;

export enum StepStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export enum StepType {
  SEARCH = 'SEARCH',
  PLANNING = 'PLANNING',
  CREATION = 'CREATION',
  CHANNELS = 'CHANNELS',
  STRATEGY = 'STRATEGY',
  FINAL = 'FINAL'
}

export interface ProcessingStep {
  id: StepType;
  label: string;
  description: string;
  status: StepStatus;
  result?: string;
}

export interface DCOContext {
  productName: string;
  productFeatures: string;
}

export interface GeneratedCreative {
  id: number;
  title: string;
  mainCopy: string;
  subCopy: string;
  imageBase64: string;
  reasoning: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { StepType, GeneratedCreative } from "../types";

const SYSTEM_INSTRUCTION = `
당신은 '큐랑(Curang)' 브랜드를 담당하는 세계 최고의 퍼포먼스 마케터입니다.
큐랑은 여행의 본질에 집중하며, 혁신적인 기능과 세련된 디자인을 갖춘 프리미엄 캐리어/여행 용품 브랜드입니다.

당신의 목표는 DCO(Dynamic Creative Optimization) 관점에서 최고의 광고 성과를 낼 수 있는 소재와 전략을 수립하는 것입니다.
항상 데이터에 기반한 논리적이고 설득력 있는 어조를 사용하십시오.
결과는 Markdown 형식으로 깔끔하게 출력해야 합니다.
`;

// Helper to get AI instance
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateStepContent = async (
  step: StepType,
  productName: string,
  productFeatures: string,
  previousContext: string,
  uploadedImages: string[] = [] // Base64 strings
): Promise<string> => {
  const ai = getAI();
  const textModel = "gemini-3-pro-preview";
  const imageModel = "gemini-3-pro-image-preview";

  let prompt = "";
  let thinkingBudget = 0;

  switch (step) {
    case StepType.SEARCH:
      prompt = `
      [STEP 1: 광고 소재 찾기]
      대상 제품: ${productName}
      특징: ${productFeatures}

      참고 이미지 개수: ${uploadedImages.length}개

      다음 작업을 수행하세요:
      1. 현재 여행 트렌드와 큐랑의 브랜드 아이덴티티를 분석하여 가장 소구력 있는 '훅(Hook)' 요소 5가지를 도출하십시오.
      2. 경쟁사 대비 차별화될 수 있는 핵심 키워드를 추출하십시오.
      3. 타겟 고객의 페르소나(여행 스타일, 라이프스타일)를 정의하십시오.
      `;
      thinkingBudget = 2048; 
      break;

    case StepType.PLANNING:
      prompt = `
      [STEP 2: 광고 소재 기획]

      이전 단계 분석 결과:
      ${previousContext}

      위 분석을 바탕으로 구체적인 DCO 소재를 기획하십시오:
      1. **비주얼 컨셉**: 이미지/영상 톤앤매너 (예: 공항, 호텔, 자연, 도심 등) 3가지 안.
      2. **카피라이팅**: 메인 헤드카피와 서브카피를 각 컨셉별로 3세트씩 작성 (클릭을 유도하는 강력한 문구).
      3. **포맷**: 숏폼(Reels/Shorts) 시나리오 1개와 정방형 이미지(Card News) 구성안 1개.
      `;
      thinkingBudget = 4096;
      break;

    case StepType.CREATION:
      return await generateAdCreatives(ai, productName, productFeatures, previousContext, uploadedImages);

    case StepType.CHANNELS:
      prompt = `
      [STEP 4: 효과적인 마케팅 채널]

      기획된 소재 및 분석:
      ${previousContext}

      이 소재들을 확산시키기 위한 최적의 미디어 믹스를 제안하십시오:
      1. **핵심 채널 선정**: (예: Meta, YouTube, TikTok, GFA 등) 및 선정 이유.
      2. **채널별 최적화 전략**: 각 플랫폼의 특성에 맞는 소재 변형 가이드.
      3. **타겟팅 설정**: 각 채널별 상세 타겟팅 옵션 (관심사, 행동, 인구통계).

      데이터를 시각화할 수 있는 표(Table) 형식을 포함하여 작성해주세요.
      `;
      thinkingBudget = 2048;
      break;

    case StepType.STRATEGY:
      prompt = `
      [STEP 5: 광고 소재 마케팅 전략]

      채널 및 소재:
      ${previousContext}

      실질적인 운영 및 성과 최적화 전략을 수립하십시오:
      1. **예산 배분**: 테스트 기간과 본 캠페인 기간의 예산 비중 (초기 ROAS 확보 전략).
      2. **A/B 테스트 설계**: 어떤 변수(카피 vs 이미지 vs 타겟)를 우선 테스트할 것인가?
      3. **KPI 설정**: 단계별 목표 지표 (CTR, CVR, ROAS 등).
      4. **인포그래픽 데이터**: 전략을 한눈에 볼 수 있는 요약 정보를 마크다운 표로 작성하세요.
      `;
      thinkingBudget = 4096;
      break;

    case StepType.FINAL:
       return "";
  }

  try {
    const parts: any[] = [{ text: prompt }];

    // Add images to context if available and relevant (mostly for SEARCH/PLANNING)
    if (step === StepType.SEARCH && uploadedImages.length > 0) {
        uploadedImages.forEach(imgBase64 => {
            parts.push({
                inlineData: {
                    mimeType: "image/png", // Assuming PNG or handling generically
                    data: imgBase64
                }
            });
        });
    }

    const response = await ai.models.generateContent({
      model: textModel,
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: thinkingBudget },
      },
    });

    return response.text || "생성된 내용이 없습니다.";
  } catch (error) {
    console.error(`Error in step ${step}:`, error);
    throw error;
  }
};

// Dedicated function to handle the complex Image Generation step
async function generateAdCreatives(
    ai: GoogleGenAI, 
    productName: string, 
    productFeatures: string, 
    context: string,
    uploadedImages: string[]
): Promise<string> {

    // 1. Plan the 5 creatives (Prompts & Copy) using JSON Schema
    const planningPrompt = `
    Based on the following context and product info, create 5 distinct, high-quality Meta (Instagram/Facebook) ad creative concepts.

    Product: ${productName}
    Features: ${productFeatures}
    Context: ${context}

    Return JSON format with 5 items. Each item must have:
    - title: Short concept title
    - imagePrompt: A highly detailed, English prompt for an AI image generator to create a photorealistic, premium advertising image (1:1 ratio). Include lighting, mood, camera angle.
    - mainCopy: Powerful Korean headline for the ad.
    - subCopy: Persuasive Korean sub-text.
    - reasoning: Why this creative works.
    `;

    const planResponse = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: planningPrompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        imagePrompt: { type: Type.STRING },
                        mainCopy: { type: Type.STRING },
                        subCopy: { type: Type.STRING },
                        reasoning: { type: Type.STRING }
                    },
                    required: ["title", "imagePrompt", "mainCopy", "subCopy", "reasoning"]
                }
            }
        }
    });

    const creativePlans = JSON.parse(planResponse.text || "[]");
    const results: GeneratedCreative[] = [];

    // 2. Generate Images for each plan (Parallel)
    const imagePromises = creativePlans.map(async (plan: any, index: number) => {
        try {
             // For image generation, if we have uploaded images, we could potentially use them as reference (img-to-img),
             // but strictly adhering to "generate creative" usually implies text-to-image for clean ad composition unless specified.
             // Given the complexity of mixing multi-image input with text prompt in API for strict output, 
             // we will rely on the powerful text prompt generated in step 1.

            const imageResponse = await ai.models.generateContent({
                model: 'gemini-3-pro-image-preview',
                contents: {
                    parts: [{ text: `Professional product photography, advertising shot. ${plan.imagePrompt}` }]
                },
                config: {
                    imageConfig: {
                        aspectRatio: "1:1",
                        imageSize: "1K"
                    }
                }
            });

            let base64Data = "";
            for (const part of imageResponse.candidates?.[0]?.content?.parts || []) {
                if (part.inlineData) {
                    base64Data = part.inlineData.data;
                    break;
                }
            }

            if (base64Data) {
                return {
                    id: index,
                    title: plan.title,
                    mainCopy: plan.mainCopy,
                    subCopy: plan.subCopy,
                    imageBase64: base64Data,
                    reasoning: plan.reasoning
                } as GeneratedCreative;
            }
            return null;
        } catch (e) {
            console.error("Image gen failed for index " + index, e);
            return null;
        }
    });

    const generatedImages = await Promise.all(imagePromises);

    // Filter out failures
    const successfulCreatives = generatedImages.filter((c): c is GeneratedCreative => c !== null);

    // Return as a special JSON string marker that ResultDisplay can parse
    return `__JSON_CREATIVE_START__${JSON.stringify(successfulCreatives)}__JSON_CREATIVE_END__`;
}

import React from 'react';
import { StepType, StepStatus, ProcessingStep } from '../types';
import { CheckCircle2, Loader2, Circle, BrainCircuit, Target, Megaphone, LineChart, FileText, Palette } from 'lucide-react';

interface StepVisualizerProps {
  steps: ProcessingStep[];
  currentStepIndex: number;
}

const getIcon = (type: StepType) => {
  switch (type) {
    case StepType.SEARCH: return <Target className="w-6 h-6" />;
    case StepType.PLANNING: return <BrainCircuit className="w-6 h-6" />;
    case StepType.CREATION: return <Palette className="w-6 h-6" />;
    case StepType.CHANNELS: return <Megaphone className="w-6 h-6" />;
    case StepType.STRATEGY: return <LineChart className="w-6 h-6" />;
    default: return <FileText className="w-6 h-6" />;
  }
};

const StepVisualizer: React.FC<StepVisualizerProps> = ({ steps, currentStepIndex }) => {
  return (
    <div className="w-full max-w-md mx-auto space-y-6">
      {steps.map((step, index) => {
        const isActive = index === currentStepIndex && step.status === StepStatus.PROCESSING;
        const isCompleted = step.status === StepStatus.COMPLETED;
        const isPending = step.status === StepStatus.IDLE;

        return (
          <div 
            key={step.id} 
            className={`relative flex items-center p-4 rounded-xl border transition-all duration-500 overflow-hidden ${
              isActive 
                ? 'bg-curang-surface border-curang-primary shadow-[0_0_15px_rgba(14,165,233,0.3)] scale-105' 
                : isCompleted 
                  ? 'bg-slate-900/50 border-curang-primary/30 opacity-80' 
                  : 'bg-slate-900/30 border-slate-700 opacity-50'
            }`}
          >
            {/* Background Animation for Active Step */}
            {isActive && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-curang-primary/10 to-transparent translate-x-[-100%] animate-[shimmer_2s_infinite]"></div>
            )}

            <div className={`mr-4 flex-shrink-0 flex items-center justify-center w-10 h-10 rounded-full border-2 ${
               isActive ? 'border-curang-primary text-curang-primary animate-pulse' : 
               isCompleted ? 'border-green-500 text-green-500 bg-green-500/10' : 
               'border-slate-600 text-slate-600'
            }`}>
              {isActive ? (
                <Loader2 className="w-5 h-5 animate-spin" />
              ) : isCompleted ? (
                <CheckCircle2 className="w-5 h-5" />
              ) : (
                <Circle className="w-5 h-5" />
              )}
            </div>

            <div className="flex-1 z-10">
              <div className="flex items-center gap-2 mb-1">
                 <span className={`${isActive ? 'text-curang-primary' : 'text-slate-400'}`}>
                    {getIcon(step.id)}
                 </span>
                 <h3 className={`font-bold text-lg ${isActive ? 'text-white' : 'text-slate-300'}`}>
                  {step.label}
                </h3>
              </div>
              <p className="text-xs text-slate-400 font-light">{step.description}</p>
            </div>

            {/* Connecting Line (except last) */}
            {index < steps.length - 1 && (
              <div className={`absolute left-[2.25rem] -bottom-8 w-0.5 h-6 ${isCompleted ? 'bg-curang-primary' : 'bg-slate-700'}`}></div>
            )}
          </div>
        );
      })}
    </div>
  );
};

