import { GoogleGenAI, Type } from "@google/genai";
import { StepType, GeneratedCreative } from "../types";

const SYSTEM_INSTRUCTION = `
당신은 '큐랑(Curang)' 브랜드를 담당하는 세계 최고의 퍼포먼스 마케터입니다.
큐랑은 여행의 본질에 집중하며, 혁신적인 기능과 세련된 디자인을 갖춘 프리미엄 캐리어/여행 용품 브랜드입니다.

당신의 목표는 DCO(Dynamic Creative Optimization) 관점에서 최고의 광고 성과를 낼 수 있는 소재와 전략을 수립하는 것입니다.
항상 데이터에 기반한 논리적이고 설득력 있는 어조를 사용하십시오.
결과는 Markdown 형식으로 깔끔하게 출력해야 합니다.
`;

// Helper to get AI instance
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// New function for Deep Research
export const runDeepResearch = async (productName: string): Promise<{ features: string; usp: string }> => {
  const ai = getAI();
  const prompt = `
  Analyze the product '${productName}' for the brand 'Curang' (Premium Travel Goods).

  Task:
  1. If this is a known product, retrieve its specific details using Google Search.
  2. If it is a new or hypothetical product, generate plausible high-end specifications consistent with Curang's brand identity (premium, innovative, stylish).

  Output Requirements:
  - Return a JSON object.
  - 'features': A detailed list of 5-7 key product features (Korean).
  - 'usp': 3 powerful Unique Selling Points that differentiate this product from competitors (Korean).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], // Enable Deep Research via Search
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            features: { type: Type.STRING },
            usp: { type: Type.STRING },
          },
          required: ["features", "usp"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("Deep Research failed:", error);
    // Fallback if search/json fails
    return {
      features: "검색에 실패했습니다. 직접 입력해주세요.",
      usp: "검색에 실패했습니다. 직접 입력해주세요."
    };
  }
};

export const generateStepContent = async (
  step: StepType,
  productName: string,
  productFeatures: string,
  productUSP: string, // Added USP parameter
  previousContext: string,
  uploadedImages: string[] = [] 
): Promise<string> => {
  const ai = getAI();
  const textModel = "gemini-3-pro-preview";

  let prompt = "";
  let thinkingBudget = 0;

  switch (step) {
    case StepType.SEARCH:
      prompt = `
      [STEP 1: 광고 소재 찾기]
      대상 제품: ${productName}
      핵심 특징: ${productFeatures}
      USP (고유 판매 제안): ${productUSP}

      참고 이미지 개수: ${uploadedImages.length}개

      다음 작업을 수행하세요:
      1. 현재 여행 트렌드와 큐랑의 브랜드 아이덴티티를 분석하여 가장 소구력 있는 '훅(Hook)' 요소 5가지를 도출하십시오.
      2. USP를 기반으로 경쟁사 대비 차별화될 수 있는 핵심 키워드를 추출하십시오.
      3. 타겟 고객의 페르소나(여행 스타일, 라이프스타일)를 정의하십시오.
      `;
      thinkingBudget = 2048; 
      break;

    case StepType.PLANNING:
      prompt = `
      [STEP 2: 광고 소재 기획]

      이전 단계 분석 결과:
      ${previousContext}

      위 분석을 바탕으로 구체적인 DCO 소재를 기획하십시오:
      1. **비주얼 컨셉**: 이미지/영상 톤앤매너 (예: 공항, 호텔, 자연, 도심 등) 3가지 안.
      2. **카피라이팅**: 메인 헤드카피와 서브카피를 각 컨셉별로 3세트씩 작성 (클릭을 유도하는 강력한 문구).
      3. **포맷**: 숏폼(Reels/Shorts) 시나리오 1개와 정방형 이미지(Card News) 구성안 1개.
      `;
      thinkingBudget = 4096;
      break;

    case StepType.CREATION:
      // Pass USP to image generation logic as well
      const creativeContext = `USP: ${productUSP}\n${previousContext}`;
      return await generateAdCreatives(ai, productName, productFeatures, creativeContext, uploadedImages);

    case StepType.CHANNELS:
      prompt = `
      [STEP 4: 효과적인 마케팅 채널]

      기획된 소재 및 분석:
      ${previousContext}

      이 소재들을 확산시키기 위한 최적의 미디어 믹스를 제안하십시오:
      1. **핵심 채널 선정**: (예: Meta, YouTube, TikTok, GFA 등) 및 선정 이유.
      2. **채널별 최적화 전략**: 각 플랫폼의 특성에 맞는 소재 변형 가이드.
      3. **타겟팅 설정**: 각 채널별 상세 타겟팅 옵션 (관심사, 행동, 인구통계).

      데이터를 시각화할 수 있는 표(Table) 형식을 포함하여 작성해주세요.
      `;
      thinkingBudget = 2048;
      break;

    case StepType.STRATEGY:
      prompt = `
      [STEP 5: 광고 소재 마케팅 전략]

      채널 및 소재:
      ${previousContext}

      실질적인 운영 및 성과 최적화 전략을 수립하십시오:
      1. **예산 배분**: 테스트 기간과 본 캠페인 기간의 예산 비중 (초기 ROAS 확보 전략).
      2. **A/B 테스트 설계**: 어떤 변수(카피 vs 이미지 vs 타겟)를 우선 테스트할 것인가?
      3. **KPI 설정**: 단계별 목표 지표 (CTR, CVR, ROAS 등).
      4. **인포그래픽 데이터**: 전략을 한눈에 볼 수 있는 요약 정보를 마크다운 표로 작성하세요.
      `;
      thinkingBudget = 4096;
      break;

    case StepType.FINAL:
       return "";
  }

  try {
    const parts: any[] = [{ text: prompt }];

    // Add images to context if available and relevant
    if (step === StepType.SEARCH && uploadedImages.length > 0) {
        uploadedImages.forEach(imgBase64 => {
            parts.push({
                inlineData: {
                    mimeType: "image/png", 
                    data: imgBase64
                }
            });
        });
    }

    const response = await ai.models.generateContent({
      model: textModel,
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: thinkingBudget },
      },
    });

    return response.text || "생성된 내용이 없습니다.";
  } catch (error) {
    console.error(`Error in step ${step}:`, error);
    throw error;
  }
};

