            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {data.map((creative) => (
                    <div key={creative.id} className="bg-slate-900 border border-slate-700 rounded-2xl overflow-hidden hover:border-curang-primary transition-colors group">
                        {/* Aspect ratio set to match 4:5 (1080x1350) */}
