           previousContext += `\n\n--- [${steps[i].label} 결과] ---\n${resultText}`;
        }

        const result = await generateStepContent(
          currentStep.id, 
          productName, 
          productFeatures, 
          productUSP,
          previousContext,
          uploadedImages
