    if (!productName) {
        alert("제품명을 입력해주세요.");
        return;
    }
    setIsResearching(true);
    try {
        const data = await runDeepResearch(productName);
        setProductFeatures(data.features);
        setProductUSP(data.usp);
    } catch (error) {
        console.error(error);
        alert("딥리서치 중 오류가 발생했습니다.");
